var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁- 킁킁-","JPN":"くんーくんくんー","ENG":"*Sniff* *Sniff*","TWN":"嗅——嗅嗅——"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Um...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아까부터 무슨 냄새를 맡고 계신 거죠?","JPN":"さっきから何の匂いを嗅いでるんですか？","ENG":"What are you trying to smell?","TWN":"你從剛才開始就在聞什麼味道？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왠지 이렇게 하면 유대감이 더 잘 느껴지더라고요.","JPN":"なんだかこうすると、連帯感をもっと強く感じられるんです。","ENG":"I feel a stronger sense of the bond when I do this for some reason.","TWN":"總覺得這樣做能更好地感受到彼此的羈絆。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"좀 더 높이 들어주실 수 있나요? 위쪽 바람이 더 잘 부는 것 같은데.","JPN":"もっと高く持ちあげてくれませんか？　上の方がよく風が吹いてるみたいですから。","ENG":"Could you hold me a little higher? I think the wind is blowing better up there.","TWN":"能再舉高一點嗎？上面的風好像更大。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이렇게요?","JPN":"こうですか？","ENG":"Like this?","TWN":"像這樣嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁 킁-","JPN":"くんくんー","ENG":"*Sniff* *Sniff*","TWN":"嗅——嗅——"},"stage":{"bg":"SKY","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그냥 냄새로 찾고 있는 것 같은데…","JPN":"ただ匂いで探してるみたいなんだけど……","ENG":"It just looks like she's trying to find him by scent...","TWN":"好像只是單純在靠氣味找人……"},"stage":{"bg":"SKY","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아무렴 어때. 괜히 지적하지 말자.","JPN":"まあ、いいか。余計なことを言うのはやめとこう。","ENG":"But who cares how? Let's not nitpick right now.","TWN":"但是無所謂啦，這種時候就別太苛求了。"},"stage":{"bg":"SKY","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"갑자기 안개가 짙어지는군.","JPN":"急に霧が濃くなったな。","ENG":"The fog is getting thicker all of a sudden.","TWN":"霧突然變濃了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이면세계에서 이런 기상이변은 결코 좋은 징조가 아니죠.","JPN":"裏世界でこのような気象異変は決していい前兆ではありません。","ENG":"Unusual weather conditions like this aren't a good sign in the Counterside.","TWN":"這種氣象在異界絕不是什麼好兆頭。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저희와 너무 떨어지지 않게 조심하십시오.","JPN":"私たちとあまり離れないように気をつけてください。","ENG":"Be careful not to be too far away from us.","TWN":"請小心，不要離我們太遠。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…응?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"방금 봤어요? 안개 사이로 사람 형체가 보였는데.","JPN":"今、見ました？　霧の中から人の形が見えたんですけど。","ENG":"Did you see that? I saw a human figure through the fog.","TWN":"你剛剛看到了嗎？霧中有一個人影。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"글쎄요. 발소리 같은 건 전혀 못 들은 것 같…","JPN":"さあ？　足音はまったく聞こえなかったと思う……","ENG":"I don't know. I didn't hear any footsteps–","TWN":"沒有……我好像完全沒聽到腳步聲……"},"stage":{"bg":"WHITE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_FIRE"},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으앗? 폭격?","JPN":"わあっ？　爆撃？","ENG":"What? An explosion?","TWN":"呃啊？子彈？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐야? 왜 갑자기 사방에서 총성이 울리는 거지?","JPN":"何？　どうしていきなり周りから銃声が聞こえるんだろう？","ENG":"Huh? Why do I suddenly hear gunshots ringing everywhere?","TWN":"怎麼了？為什麼突然哪裡都是槍聲……！？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식파 때문인가? 여태 잠잠한 줄 알았던 전쟁 PTSD가 이제 와서 사춘기처럼 폭발한 건가?","JPN":"侵食波のせいかな？　今まで潜在していた戦争のPTSDが今更爆発した？","ENG":"Is it because of the Corruption ray? Or has my war-related PTSD, which was dormant until now, suddenly been triggered like puberty?","TWN":"是因為侵蝕波嗎？還是說我一直以為平靜下來的戰後PTSD，終於像青春期一樣爆發了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 그렇다기엔…","JPN":"でも、それにしては……","ENG":"But for something like that to happen...","TWN":"但要這麼說的話……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…난 이런 장소는 한 번도 와본 적 없는데?","JPN":"……私、こんな場所には一度も来た覚えがないんだけど？","ENG":"...I've never been to a place like this before.","TWN":"……我從來沒來過這種地方？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"사도가 너무 강해요! 벌써 절반이 당했습니다!","JPN":"使徒が強すぎます！　もう半分がやられました！","ENG":"The Apostle's too strong! Half of our units have already been wiped out!","TWN":"使徒太強了！我們已經損失了一半人手！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"이대로는 승산이 없어.","JPN":"このままだと勝ち目がない。","ENG":"We're all doomed.","TWN":"我們這樣根本沒有勝算。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전대장님께서 말씀하신 차선책대로 해! 최대한 흩어져서 시간을 버는 거다!","JPN":"戦隊長がおっしゃった次善策どおりにしろ！　なるべく散開して時間を稼ぐんだ！","ENG":"Let's do what Commander said and go with Plan B! Everyone, scatter as much as possible to buy the others time!","TWN":"按照隊長說的備用方案行動！分散開來爭取時間！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"군인…?","JPN":"軍人……？","ENG":"Soldiers...?","TWN":"士兵……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니야. 저 복장은 관리국이랑 비슷해.","JPN":"違う。あの服装は管理局と似てる。","ENG":"No. Those uniforms are similar to the Administration's.","TWN":"不對，那些制服和管理局的很像。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 시신들의 상처, 전부 날카로운 것에 베였어.","JPN":"この死体の傷、全部鋭利な物で斬られたんだ。","ENG":"The wounds on the corpses. They were all cut by something sharp.","TWN":"這些屍體的傷口，全都是被鋒利的東西割開的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"칼에 베인 상처는 아닌 것 같은데…","JPN":"刃物じゃないみたいだけど……","ENG":"It doesn't look like it's from a sword...","TWN":"好像不是刀傷……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"발소리가… 둘. 이쪽으로 가까워지고 있어.","JPN":"足音が……2つ。こっちに近づいてる。","ENG":"Two different footsteps... and they're getting closer this way.","TWN":"腳步聲……兩個人。正朝這邊靠近。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"함께 움직인다기 보단… 한쪽이 쫓기고 있는 건가?","JPN":"一緒に動いているというより……片方が追われてるのかな？","ENG":"It doesn't sound like they're together... Is one chasing the other?","TWN":"與其說是一起行動……不如說是一方在被追趕？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"으윽…!","JPN":"ううっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"숨을 수 있을 줄 알았어?","JPN":"隠れられるとでも思ったのか？","ENG":"Did you really think you could hide from me?","TWN":"你以為能躲得了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 피를 질질 흘리고 다니면, 냄새로 찾아낼 수 밖에 없잖아. 사냥감.","JPN":"それだけ血を流してたら、匂いで探せるんだ。獲物。","ENG":"I can spot you right away when you're bleeding that much, prey.","TWN":"流了那麼多血，我只靠氣味就找到你了，獵物。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"허억… 윽…","JPN":"はあ……うっ……","ENG":"Gah... Ngh...","TWN":"呼……呃……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"분명 목을 노렸을 텐데… 벌써 회복했다고…?","JPN":"確かに首を狙ったはずだが……もう回復しただと……？","ENG":"I aimed for your neck... but you've already recovered...?","TWN":"明明瞄準了脖子……已經恢復了嗎……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"큭큭, 확실히 방금 네 무리의 전략은 놀랍긴 했어. 마치 내 움직임을 읽는 것 같았거든.","JPN":"ククッ、さっきのあんたの群れの戦略には本当に驚いた。まるでアタシの動きを読んでいるかのようだったからな。","ENG":"Keke. Your strategy did catch me off guard. It was as if you were reading my movements.","TWN":"呵呵，你的策略確實讓我放鬆了警惕。就好像能看穿我的動作一樣。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하지만 겨우 내게 그 정도 상처를 입혔다고 이긴 줄 착각하다니…","JPN":"だが、アタシにこの程度の傷を負わせて勝ったと勘違いするなんて……","ENG":"But I can't believe you thought you won with a graze wound...","TWN":"但是你居然以為僅僅給我造成這種程度的傷害就贏了……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"평범한 인간답게 머리 쓰는 것도 평범하네.","JPN":"普通の人間らしく、頭の回転も普通だな。","ENG":"I guess ordinary people think ordinarily too.","TWN":"果然是個普通人，想得也很簡單呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"늑대… 사람…?","JPN":"オオカミ……人間……？","ENG":"A were... wolf...?","TWN":"狼……人……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그리고 저 앞에 있는 사람은…","JPN":"それに、あの前にいる人は……","ENG":"And that person over there is...","TWN":"然後，前面的那個人是……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…펠릭스?","JPN":"……フェリックス？","ENG":"...Felix?","TWN":"……緋莉克絲？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 본부… 본 무전은 클리파 차원 내의 관리국 인원들에게 전파하는 단방향 발신이다.","JPN":"こちら、本部……この無線はクリファ次元内の管理局全員に伝える単方向発信だ。","ENG":"This is HQ... This radio is a one-way transmission to all Administration personnel within the Qlipha Dimension.","TWN":"這裡是總部……本次無線電為單向發送給逆卡巴拉次元內管理局人員的通訊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"늑대의 사망을 확인했다. 목표 달성은 실패다.","JPN":"オオカミの死亡を確認した。目標の達成は失敗だ。","ENG":"The Wolf is confirmed dead. We have failed to achieve our goal.","TWN":"確認狼已死亡。目標未能達成。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 생존자는 신속하게 클리파 차원에서 철수하라.","JPN":"残りの生存者は速やかにクリファ次元から撤退しろ。","ENG":"All remaining survivors must quickly withdraw from the Qlipha Dimension.","TWN":"剩餘的生存者請迅速從逆卡巴拉次元撤離。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"반복한다. 대피가 가능한 관리국 대원은 즉시 클리파 차원에서 철수…","JPN":"繰り返す。退避可能な管理局隊員は直ちにクリファ次元から撤退……","ENG":"I repeat. All Administration personnel who are able should immediately evacuate from the Qlipha Dimension...","TWN":"重複。能夠撤離的管理局隊員請立即從逆卡巴拉次元撤離……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 됐다는군.","JPN":"そうみたいだな。","ENG":"So it seems.","TWN":"事情就是這樣。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SERIOUS"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"클리포트 게임에서 패배한 마당에, 철수한다고 해서 뭐가 달라질진 모르겠지만,","JPN":"クリフォトゲームで負けた今､撤退しても何も変わらないと思うんだが。","ENG":"I don't know what use it is for losers to flee after losing the Qliphoth Game, but...","TWN":"雖然不知道在決鬥中輸了的傢伙逃出去後還有什麼用……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"여기에 갇힌 넌 그마저도 할 수도 없겠…","JPN":"ここに閉じ込められたあんたはそれさえもできな……","ENG":"You're trapped here, so you can't even do–","TWN":"啊，被困在這裡的你，連那個也——"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"응?","JPN":"む？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"뭐야. 이제 도망치는 것도 포기하고 죽을 셈이냐? 시시하게.","JPN":"何だ。もう逃げることさえ諦めて死ぬつもりか？　つまらないな。","ENG":"What? Have you given up on running away and accepted your death? How boring.","TWN":"什麼啊。現在連逃跑都放棄了，打算去死嗎？真無聊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"방법이 있을 거야.","JPN":"方法があるはずだ。","ENG":"There must be a way.","TWN":"一定有辦法的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리가 사도를 죽이고 늑대를 살려서, 클리포트 게임을 이길… 더 나은 방법이…","JPN":"私たちが使徒を殺してオオカミを蘇らせ、クリフォトゲームに勝つ……もっといい方法が……","ENG":"A better way... for us to kill the Apostles and save the Wolf... to win the Qliphoth Game...","TWN":"殺死使徒、救下狼、贏得逆卡巴拉遊戲……一定會有更好的方法的……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안돼…! 그러지 마!","JPN":"ダメ……！　やめて！","ENG":"No...! Don't do it!","TWN":"不要……！不要這樣！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"한 번 더…","JPN":"もう1度……","ENG":"One more attempt...","TWN":"再來一次……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사라졌어…?","JPN":"消えた……？","ENG":"Where did she go...?","TWN":"她們去哪了……？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여긴…","JPN":"ここは……","ENG":"Is this...","TWN":"這裡是……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"묘지?","JPN":"墓地？","ENG":"a graveyard?","TWN":"墓地？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"안개가 걷혔군.","JPN":"霧が消えたな。","ENG":"The fog is clearing.","TWN":"霧散了。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님…?","JPN":"社長……？","ENG":"Boss...?","TWN":"老闆……？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"방금 그건 뭐였죠?","JPN":"今のは何だったんですか？","ENG":"What was that just now?","TWN":"剛剛那個到底是什麼？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국이 패배를 경험했던 수많은 전투 중 하나일세.","JPN":"管理局が敗北した数多くの戦闘の中の1つだ。","ENG":"It is one of the many battles in which the Administration experienced defeat.","TWN":"這是管理局經歷的眾多失敗作戰之一。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이곳에서 벌어진 과거의 단편이기도 하지.","JPN":"ここで繰り広げられた過去の断片でもある。","ENG":"It is also a fragment of the past that happened here.","TWN":"也是過去在這裡發生的某個片段。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 눈으로 이런 광경을 다시 보게 될 줄은 몰랐군.","JPN":"自分の目でまたこんな光景を見ることになるとはな。","ENG":"I never thought I'd see that day again with my own eyes.","TWN":"沒想到我還能再次目睹這樣的場面……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아무래도 이것의 영향인 것 같군요.","JPN":"どうやらこれの影響のようですね。","ENG":"I assume it is the effect of this.","TWN":"看來是受到了這個的影響。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리국에서 보관 중이던 <color=#ffd34c>잠망경</color>입니다.","JPN":"管理局で保管していた<color=#ffd34c>潜望鏡</color>です。","ENG":"This is the <color=#ffd34c>Periscope</color> kept by the Administration.","TWN":"管理局保管的<color=#ffd34c>潛望鏡</color>。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 큐브가 저희한테 과거를 보여준 거라고요? 관리국은 그런 것도 가능한 건가요?","JPN":"このキューブが私たちに過去を見せてくれたんですか？　管理局ってそんなこともできるんですか？","ENG":"This cube is what showed us the past? The Administration is capable of that, too?","TWN":"剛剛就是這個立方體為我們展示過去景象的嗎……？管理局連這種事都能做到……？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리국이 보관 중인 대부분의 아티팩트는 저희도 그 원리를 명확히 모릅니다.","JPN":"管理局が保管しているほとんどのアーティファクトは、私たちもその原理を明確に理解していません。","ENG":"We are also not sure on the principles of most of the Artifacts kept by the Administration.","TWN":"管理局保管的大部分神器，我們也不清楚其原理。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"카운터의 워치처럼 그 용도만 어렴풋이 이해하고 있을 뿐이죠.","JPN":"カウンターのウォッチのように、その使い道だけをなんとなく理解しているだけです。","ENG":"Like a Counter's Watch, we only vaguely understand how they are used.","TWN":"就像制裁者的能量環一樣，我們只是模糊地理解它們的用途而已。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗, 이거예요.","JPN":"あっ、これです。","ENG":"Oh, that's it.","TWN":"啊，是這個。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 물건에서 잭슨 씨의 유대감이 느껴져요.","JPN":"これからジャクソンさんの連帯感が感じられます。","ENG":"I feel Jackson's bond from that object.","TWN":"從這件物品中能感受到傑森的羈絆。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠망경은 챔버에서 관리하는 아티팩트지.","JPN":"潜望鏡はチェンバーで管理しているアーティファクトだ。","ENG":"The Periscope is an Artifact that Chamber managed.","TWN":"潛望鏡是由強巴管理的人造神器。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잭슨이 시니어 권한으로 이걸 반출했던 모양이군.","JPN":"ジャクソンがシニアの権限でこれを搬出したようだな。","ENG":"It seems that Jackson used his Senior authority to take it with him.","TWN":"看起來是傑森利用Senior許可權把它給帶出來了。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 정작 당사자가 이곳에 없으니, 여기까지 가져온 목적을 알 수 없군요.","JPN":"ですがその当事者がここにいないので、ここまで持ってきた目的はわかりません。","ENG":"But since he's not here, we have no clue why he brought it all the way here.","TWN":"但是當事人不在這裡，所以不知道把它帶到這裡的目的是什麼。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시로코바. 아티팩트에 남은 냄새로 당신의 주인을 찾을 순 없습니까?","JPN":"シロコバ。アーティファクトに残っている匂いであなたの主を探すことはできないんですか？","ENG":"Shirokova. Can you find your master with the smell remaining on the Artifact?","TWN":"西羅科娃，你能透過神器上殘留的氣味找到你的主人吧？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와앗, 방금 이 사람 절 개 취급한 거죠? 그쵸?!","JPN":"わあっ、今この人、私のことを犬扱いしましたよね？　そうですよね！？","ENG":"Wow, did she just treat me like a dog?!","TWN":"哇啊，這個人剛才把我當成小狗狗了吧？對吧？！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아무렴 어떻습니까, 범죄자. 그 코로 당신을 구해준 관리자님께 쓸모를 증명하십시오.","JPN":"いいではないですか、犯罪者。その鼻であなたを助けてくれた最高管理者様に自分の利用価値を証明しなさい。","ENG":"No one cares, criminal. Now prove your usefulness to the Administrator with that nose of yours.","TWN":"不管怎樣，罪犯。用你的鼻子向拯救你的管理者證明你的價值吧。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"꺄아- 그렇게 코에 문지른다고 냄새로 찾아지는 게 아녜요!","JPN":"きゃあっー！　そうやって鼻にこすりつけても匂いで探せるわけじゃないんです！","ENG":"KYAAAH! Smashing my nose into it doesn't make me smell it any better!","TWN":"欸欸欸——！就算這樣用鼻子聞，也找不到的！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저도 잭슨 씨를 찾고 싶지만 유대감이 이면세계의 차원벽까지 뚫진 못한다고요!","JPN":"私もジャクソンさんを探したいんですけど、連帯感が裏世界の次元壁まで貫いたりはしませんよ！","ENG":"I also want to find Mr. Jackson, but our bond can't go through the Counterside's dimensional wall!","TWN":"我也想找到傑森，但我們的羈絆無法穿透異界的次元牆壁啊！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말은, 같은 공간에만 있으면 그 유대감으로 찾아낼 수 있단 뜻인가?","JPN":"それはつまり、同じ空間にさえいればその連帯感で探せるという意味なのかね？","ENG":"So what you're saying is that you can find this bond if you're in the same space?","TWN":"你的意思是，只有在同一個空間裡，才能通過這種羈絆找到對方嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네! 지금까지도 그래왔으니까요!","JPN":"はい！　今までもそうしてきました！","ENG":"Yes! It's always been like that!","TWN":"是的！一直以來都是這樣的！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저기. 제가 계속 이렇게 있으면 여러분도 불편할 텐데, 피 좀 나눠주시면 안 될까요?","JPN":"あの。私がずっとこんな姿でいるとみなさんも不便だと思いますから、ちょっと血を分けてもらえませんか？","ENG":"Um. I assume that it'll be a hassle for all of you if I stay like this, so could I get some blood?","TWN":"那個。我一直這副模樣的話，你們也會不方便的，能分點血給我嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"피가 있으면 몸을 다시 재생할 수 있거든요.","JPN":"血をもらえばまた体を再生できるんです。","ENG":"I'll be able to regenerate my body if I do.","TWN":"有血的話，身體就可以再生了。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람의 피라면 아무거나 괜찮은 건가?","JPN":"人の血ならなんでもいいのかね？","ENG":"Will any human blood do?","TWN":"只要是人的血就可以嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"기왕이면 여자 피가 효과가 더 좋아요! 더 향긋하기도 하고요!","JPN":"せっかくなら女性の血が効果的なんです！　もっと香ばしいですし！","ENG":"Well, the effects are better when the blood is from a woman! Plus, it's more fragrant!","TWN":"既然如此，女人的血效果更好！而且更香！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어라라? 왜 갑자기 다들 시선을 피하는 거죠?!","JPN":"あれれ？　どうしてみんな視線を逸らすんですか！？","ENG":"Oh? Why is everyone suddenly looking away?","TWN":"欸欸欸——？大家為什麼突然都避開視線？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럼, 아쉬운대로 관리자님 거라도-","JPN":"じゃあ、残念ですけど管理者さんの血でもー","ENG":"Then, I guess the Administrator's blood will do.","TWN":"那麼，就勉強用管理者的吧～"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"이런 곳에서 헌혈을 하게 될 줄은 몰랐는데.","JPN":"こんなところで献血をすることになるとはな。","ENG":"Didn't think I'd be donating blood at a place like this.","TWN":"沒想到會在這種地方獻血。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"양치는 제대로 해뒀길 바라네.","JPN":"歯はちゃんと磨いただろうな？","ENG":"I hope you brushed your teeth, at least.","TWN":"希望你有好好刷牙。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잠시 기다려주시죠, 관리자님.","JPN":"少しお待ちください、最高管理者様。","ENG":"Wait, Administrator.","TWN":"請稍等一下，管理者。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리국 공인의 신분이 위조되었음을 확인한 시점에서, 저희는 시로코바라는 인물을 함부로 신뢰해선 안 됩니다.","JPN":"管理局公認の身元が偽装されたことを確認した時点で、私たちはシロコバという人物をむやみに信頼してはいけません。","ENG":"Since we have confirmed that the identity of an Administration official has been forged, we must not fully trust this Shirokova person.","TWN":"既然管理局認證的身份是偽造的，我們便不能輕信這個名為西羅科娃的人物。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"몸을 되찾으면 저희에게 위협을 가하거나 도망칠 가능성이 있으니, 지금은 그대로 두는 편이 좋을 것 같군요.","JPN":"体を取り戻せば私たちを脅かしたり逃げる可能性がありますので、今はあのままにしておいた方が良さそうです。","ENG":"There is a chance that she might threaten us or flee as soon as she regains her body. So, I suggest we leave her like this for now.","TWN":"如果讓她恢復身體，可能會逃跑，甚至對我們造成威脅，所以現在最好就這樣放著不管。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 하는군.","JPN":"そういうことだ。","ENG":"So she says.","TWN":"她這麼說呢。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하지만 지금은 그 상태로 우리와 함께 해줘야겠네.","JPN":"すまないが、今はその状態で私たちと一緒に行動してくれたまえ。","ENG":"I'm sorry, but you'll have to come with us like this for now.","TWN":"很抱歉，現在你只能保持這個狀態和我們在一起了。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럴 수가아-!","JPN":"そんなぁー！","ENG":"NOOOO!","TWN":"怎麼會這樣啊——！"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님? 어디 가세요?","JPN":"社長？　どこに行くんですか？","ENG":"Boss? Where are you going?","TWN":"老闆？你要去哪？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"묘지 한복판에 눈에 띄는 물건이 있어서 말이야.","JPN":"墓地の真ん中に気になる物があるのでね。","ENG":"There's something that stands out in the middle of the graveyard.","TWN":"在墓地的中央有一個很顯眼的東西。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"오… 이건 꽃반지네요.","JPN":"おお……これは花の指輪ですね。","ENG":"Ooh... it's a flower ring.","TWN":"啊……這是花戒指呢。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"꽃잎이 샛노란 게 아직도 살아있는 것 같아요.","JPN":"花びらの黄色が鮮やかで、まだ生きているみたいです。","ENG":"The petals are still yellow, like it's still alive.","TWN":"鮮黃的花瓣，彷彿還活著一樣。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이면세계에선 꽃이 피어나지 않는 것처럼, 시들지도 않습니다.","JPN":"裏世界では花が咲かないように、枯れることもありません。","ENG":"Just like how flowers don't bloom in the Counterside, they don't wither either.","TWN":"異界裡的花不會綻放，同樣也不會枯萎。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"누군가 이곳에 묘지를 세운 것처럼, 헌화하기 위해 꽃반지를 가져다 둔 걸지도 모르죠.","JPN":"誰かがここに墓地を作ったように、花を供えるために花の指輪を置いたのかもしれません。","ENG":"Someone must have placed the flower ring to lay a wreath much like how someone decided to make a graveyard here.","TWN":"就好像有人在這裡蓋了一個墓地，然後又有人為了獻花而帶來了花圈一樣。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이면세계에 바치는 꽃이라…","JPN":"裏世界に捧げる花か……","ENG":"A flower offered to the Counterside...","TWN":"獻給異界的花……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어떤 꽃이길래 여기까지 가져온 걸까요?","JPN":"ここまで持ってくるなんて、どんな花なんでしょうか？","ENG":"What kind of flower would someone bring all the way here?","TWN":"是什麼花，那個人竟然不惜大老遠地帶到這裡？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…금잔화.","JPN":"……キンセンカ。","ENG":"...A Calendula.","TWN":"……金盞花。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 이름의 꽃일세.","JPN":"そういう名前の花さ。","ENG":"That is this flower's name.","TWN":"這是那朵花的名字。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"예쁘네요.","JPN":"綺麗ですね。","ENG":"That's a pretty name.","TWN":"唔，很漂亮的名字呢。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"혹시 묘지에 이 꽃을 둔 게 사장님이나 지인분인가요?","JPN":"もしかして墓地にこの花を置いた人が社長とお知り合いの方なんですか？","ENG":"Was it you or someone you know who put this flower here?","TWN":"難道是老闆或者你的熟人把花放在這裡的嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제 추측이긴 하지만, 다른 세계의 사람들을 기억하고 추모할 사람이 그렇게 흔하진 않을 것 같아서요.","JPN":"私の推測ですけど、他の世界の人たちを忘れず追悼する人がそんなにいるとは思えないんですよ。","ENG":"It's just a guess, but I don't think it's common for people to remember and commemorate people from another world.","TWN":"我只是猜一猜，畢竟能記住這裡，並來悼念其他世界的人並不多。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말대로… 이면세계가 현실이었던 과거를 기억하는 사람은 거의 없지.","JPN":"そのとおり……裏世界が現実だった過去を記憶している人はほとんどいない。","ENG":"Like you said... there are almost none who remembers the past when the Counterside used to be our world.","TWN":"你說得很對……幾乎沒有人記得異界曾經也是現世。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만…","JPN":"だが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 넓은 묘지를 어느 누가 만들었는진, 나도 모르겠군.","JPN":"ここまで広い墓地を誰が作ったのかは、私にもわからない。","ENG":"I don't know who made this vast graveyard.","TWN":"就算是我也不知道，這麼大的墓地到底是誰蓋的。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"드라이브 안정화 완료. 왕복 항행 시스템을 통해 현실로 부상하겠습니다.","JPN":"ドライブの安定化が完了。往復航行システムを通じて現実へと浮上します。","ENG":"Drive stabilization complete. Reemerging to the Normalside through the round-trip navigation system.","TWN":"驅動穩定化完成。將透過往返導航系統躍出到現世。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여러 일이 있었지만, 정작 시니어 분은 못 찾았네요.","JPN":"色んなことがありましたけど、肝心のシニアは見つけられませんでしたね。","ENG":"A lot of things happened, but we couldn't find the Senior.","TWN":"雖然發生了很多事，但最終還是沒能找到那個Senior……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"중요한 건 진전이 있다는 거지.","JPN":"重要なのは進展があったということさ。","ENG":"What's important is that we made progress.","TWN":"重要的是我們有進展了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잭슨과 깊이 연루된 카운터 한 명과 아티팩트도 찾았으니…","JPN":"ジャクソンと深い関係のあるカウンターが1人とアーティファクトも見つかったから……","ENG":"We did find a Counter and an Artifact that are deeply involved with Jackson–","TWN":"既然找到了與傑森關聯很深的制裁者和人造神器……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님…?","JPN":"社長……？","ENG":"Boss...?","TWN":"老闆……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"啊啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님! 눈 좀 떠보세요!","JPN":"社長！　しっかりしてください！","ENG":"Boss! Wake up!","TWN":"老闆！你快醒醒啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님! 괜찮으십니까?!","JPN":"最高管理者様！　大丈夫ですか！？","ENG":"Administrator! Are you all right?!","TWN":"管理者！你沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"역시 침식지대에 머문 부작용이…!","JPN":"やはり侵食地帯にいた副作用が……！","ENG":"It's because of the side effects of staying in the Corrupted Area for too long...!","TWN":"果然是滯留在侵蝕區域的副作用……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 괜찮아. 그리고 침식 때문은 아니니 걱정 말게.","JPN":"私は大丈夫だ。それに侵食のせいではないから心配しなくてもいい。","ENG":"I'm fine. And it's not because of the Corruption, so don't you worry.","TWN":"我沒事。而且不是因為侵蝕，不用擔心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"간만의 여정에 좀 피곤해서 그럴 뿐이니… 도착할 때까지 잠시 눈 좀 붙여도 괜찮겠나?","JPN":"久々の旅で疲れてるだけだから……到着するまでしばらく目を閉じていてもいいかね？","ENG":"I'm just a little tired from the long journey... Will it be okay if I rest my eyes for a while until we arrive?","TWN":"只是久違的旅行有些疲憊……在回到現世之前，能讓我稍微眯一會下嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으음… 정말로 피곤한 것 뿐이라면 그나마 다행이네요.","JPN":"うーん……本当に疲れてるだけならよかったですね。","ENG":"Mm... It could be worse, but I'm glad it's because you're just exhausted.","TWN":"嗯……幸好只是單純的疲憊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……承知しました。","ENG":"...Understood.","TWN":"……我明白了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"도착하기까지 아직 시간이 남았으니, 편히 쉬십시오.","JPN":"到着するまでまだ時間がありますので、お休みください。","ENG":"There is still time until we arrive, so please rest.","TWN":"離躍出還有一段時間，請安心休息吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};